import{_ as t,o as i,c as a,a2 as o}from"./chunks/framework.CpXckY1Z.js";const u=JSON.parse('{"title":"Migration from v1","description":"","frontmatter":{},"headers":[],"relativePath":"guide/migration-v1.md","filePath":"guide/migration-v1.md","lastUpdated":1784533055000}'),r={name:"guide/migration-v1.md"};function s(d,e,n,c,l,h){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="migration-from-v1" tabindex="-1">Migration from v1 <a class="header-anchor" href="#migration-from-v1" aria-label="Permalink to &quot;Migration from v1&quot;">​</a></h1><p>v2 splits the single <code>rapiq</code> package into focused <code>@rapiq/*</code> packages and replaces string-building with a typed query AST. This page is a running log of the intentional changes — it is assembled into a full step-by-step guide as v2 stabilizes.</p><div class="info custom-block"><p class="custom-block-title">v1 docs</p><p>The v1 documentation lives on the <a href="https://github.com/tada5hi/rapiq/tree/v1" target="_blank" rel="noreferrer">v1 branch</a>.</p></div><h2 id="package-split" tabindex="-1">Package split <a class="header-anchor" href="#package-split" aria-label="Permalink to &quot;Package split&quot;">​</a></h2><table tabindex="0"><thead><tr><th>v1</th><th>v2</th></tr></thead><tbody><tr><td><code>rapiq</code> (everything)</td><td><code>@rapiq/core</code> + the packages for your side of the wire — see <a href="/guide/installation.html">Installation</a></td></tr></tbody></table><h2 id="api-mapping" tabindex="-1">API mapping <a class="header-anchor" href="#api-mapping" aria-label="Permalink to &quot;API mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>v1</th><th>v2</th></tr></thead><tbody><tr><td><code>buildQuery(input)</code> → string</td><td><a href="/guide/building-queries.html"><code>defineQuery(input)</code></a> → <code>Query</code>, then <code>createURLCodec().encode(query)</code></td></tr><tr><td><code>parseQuery(input, options)</code></td><td><a href="/guide/wire.html"><code>createURLCodec(registry).decode(input, { schema })</code></a> for URL input; <a href="/packages/parser-simple.html"><code>SimpleParser</code></a> for canonical object input</td></tr><tr><td>per-call allow-list options</td><td>a named <a href="/guide/schemas.html"><code>Schema</code></a> in a <code>SchemaRegistry</code></td></tr></tbody></table><h2 id="behavior-changes" tabindex="-1">Behavior changes <a class="header-anchor" href="#behavior-changes" aria-label="Permalink to &quot;Behavior changes&quot;">​</a></h2><h3 id="filters-prefix-position-breaking" tabindex="-1">Filters: <code>~</code> prefix position (breaking) <a class="header-anchor" href="#filters-prefix-position-breaking" aria-label="Permalink to &quot;Filters: `~` prefix position (breaking)&quot;">​</a></h3><p>In v1, <code>~text</code> meant <em>starts with</em> (<code>text%</code>) — the only LIKE form the dialect had. v2 uses a richer, position-based mapping:</p><table tabindex="0"><thead><tr><th>Wire value</th><th>v1</th><th>v2</th></tr></thead><tbody><tr><td><code>text~</code></td><td>—</td><td>starts with (<code>text%</code>)</td></tr><tr><td><code>~text</code></td><td>starts with (<code>text%</code>)</td><td>ends with (<code>%text</code>)</td></tr><tr><td><code>~text~</code></td><td>—</td><td>contains (<code>%text%</code>)</td></tr></tbody></table><p><strong>v1 clients sending <code>~text</code> change meaning from starts-with to ends-with.</strong> Rewrite them to <code>text~</code> — or move to typed <a href="/guide/building-queries.html#condition-helpers">condition helpers</a> / the <a href="/packages/codec-url.html#expression-dialect">expression dialect</a>, which have no positional magic.</p><h3 id="filters-magic-value-strings-are-wire-only" tabindex="-1">Filters: magic value strings are wire-only <a class="header-anchor" href="#filters-magic-value-strings-are-wire-only" aria-label="Permalink to &quot;Filters: magic value strings are wire-only&quot;">​</a></h3><p>v1 accepted <code>&#39;&gt;=18&#39;</code>, <code>&#39;~jo~&#39;</code>, <code>&#39;!null&#39;</code> as <em>build input</em>. In v2, the string prefixes remain part of the wire format only — build input uses operator objects (<code>{ $gte: 18 }</code>, <code>{ $contains: &#39;jo&#39; }</code>, <code>{ $ne: null }</code>) or condition helpers.</p><h3 id="expression-dialect-quoted-values-are-never-comma-split" tabindex="-1">Expression dialect: quoted values are never comma-split <a class="header-anchor" href="#expression-dialect-quoted-values-are-never-comma-split" aria-label="Permalink to &quot;Expression dialect: quoted values are never comma-split&quot;">​</a></h3><p><code>eq(name, &#39;a,b&#39;)</code> now parses to the plain string <code>&#39;a,b&#39;</code>. Lists are expressed as separate arguments (<code>in(status, &#39;a&#39;, &#39;b&#39;)</code>), not comma strings.</p><h3 id="codecs-loud-failures-instead-of-silent-lossiness-breaking" tabindex="-1">Codecs: loud failures instead of silent lossiness (breaking) <a class="header-anchor" href="#codecs-loud-failures-instead-of-silent-lossiness-breaking" aria-label="Permalink to &quot;Codecs: loud failures instead of silent lossiness (breaking)&quot;">​</a></h3><p>v1&#39;s URL build silently emitted whatever it was given. v2&#39;s <code>encode</code> throws typed errors (<code>FEATURE_UNSUPPORTED</code>, <code>OPERATOR_UNSUPPORTED</code>) for queries the wire dialect cannot represent. The default expression dialect carries nested compounds, <code>or(...)</code> and same-field conditions natively, so its typed failures are limited to operators without a grammar production (regex/mod/exists/elemMatch) and values that would decode to a different condition. Only the deprecated explicit simple encoding (<code>URL_SIMPLE_CODEC</code>) additionally rejects nested compounds, <code>or(...)</code> and same-field conditions. See <a href="/guide/wire.html#what-fits-on-the-wire">What fits on the wire</a>.</p><h3 id="url-filters-expression-output-legacy-input" tabindex="-1">URL filters: expression output, legacy input <a class="header-anchor" href="#url-filters-expression-output-legacy-input" aria-label="Permalink to &quot;URL filters: expression output, legacy input&quot;">​</a></h3><p>The v2 URL codec writes stamped expression filters by default. Its decoder still recognizes v1-style bracket filters, so deploy receiving applications before switching callers. Deprecated simple encoding remains available explicitly with <code>URL_SIMPLE_CODEC</code> during the v2 migration.</p><h3 id="filters-string-equality-is-case-insensitive-breaking" tabindex="-1">Filters: string equality is case-insensitive (breaking) <a class="header-anchor" href="#filters-string-equality-is-case-insensitive-breaking" aria-label="Permalink to &quot;Filters: string equality is case-insensitive (breaking)&quot;">​</a></h3><p>In v1, <code>eq</code>/<code>in</code> on strings delegated case behavior to the database — the same query matched <code>Super Hero</code> for <code>super hero</code> on MySQL (<code>*_ci</code> collation) but not on Postgres. v2 normalizes the whole equality family (<code>eq</code>, <code>ne</code>, <code>in</code>, <code>nin</code>) <strong>and</strong> the anchored operators (<code>contains</code>, <code>startsWith</code>, <code>endsWith</code>) to case-insensitive string matching on every backend; <code>@rapiq/sql</code> renders <code>lower(field) = lower(?)</code> on case-sensitive dialects. Opt identifier/token fields out with the schema&#39;s <a href="/guide/filters.html#case-sensitivity"><code>caseSensitive</code></a> list.</p><h2 id="coming-from-typeorm-extension" tabindex="-1">Coming from typeorm-extension? <a class="header-anchor" href="#coming-from-typeorm-extension" aria-label="Permalink to &quot;Coming from typeorm-extension?&quot;">​</a></h2><p>The server-pipeline differences (strict mode, join defaults, <code>applyQuery</code>) have <a href="/guide/migration-typeorm-extension.html">their own page</a>.</p>',24)])])}const m=t(r,[["render",s]]);export{u as __pageData,m as default};
